"#ifndef RAD_I2S_H
#define RAD_I2S_H

#include <Arduino.h>
#include <driver/i2s.h>

namespace RadDSP {

class I2S {
public:
    I2S();
    ~I2S();

    /**
     * @brief Initialize I2S port
     * @param port I2S_NUM_0 or I2S_NUM_1
     * @param sampleRate The sampling rate (e.g. 44100, 48000)
     * @param bckPin Bit Clock (BCLK) pin
     * @param wsPin Word Select (LRCLK) pin
     * @param dataOutPin Data Out (TX) pin (Set to -1 if unused)
     * @param dataInPin Data In (RX) pin (Set to -1 if unused)
     * @param useInternalDAC Set to true if using internal DAC
     * @return true if successful
     */
    bool begin(i2s_port_t port = I2S_NUM_0, 
               int sampleRate = 48000, 
               int bckPin = 26, 
               int wsPin = 25, 
               int dataOutPin = 22, 
               int dataInPin = -1,
               bool useInternalDAC = false);

    /**
     * @brief Read data from I2S
     * @param dest Buffer to store the read data
     * @param size Size in bytes to read
     * @return Number of bytes actually read
     */
    size_t read(void* dest, size_t size);

    /**
     * @brief Write data to I2S
     * @param src Buffer containing data to write
     * @param size Size in bytes to write
     * @return Number of bytes actually written
     */
    size_t write(const void* src, size_t size);

    /**
     * @brief Uninstall I2S driver
     */
    void end();

private:
    i2s_port_t _port;
    bool _initialized;
};

} // namespace RadDSP

#endif // RAD_I2S_H
"

"#include "RadI2S.h"

namespace RadDSP {

I2S::I2S() : _port(I2S_NUM_0), _initialized(false) {
}

I2S::~I2S() {
    if (_initialized) {
        end();
    }
}

bool I2S::begin(i2s_port_t port, int sampleRate, int bckPin, int wsPin, int dataOutPin, int dataInPin, bool useInternalDAC) {
    if (_initialized) return true; // Already initialized

    _port = port;

    i2s_mode_t mode = (i2s_mode_t)(I2S_MODE_MASTER);
    if (dataOutPin >= 0 || useInternalDAC) {
        mode = (i2s_mode_t)(mode | I2S_MODE_TX);
    }
    if (dataInPin >= 0) {
        mode = (i2s_mode_t)(mode | I2S_MODE_RX);
    }

    if (useInternalDAC) {
        mode = (i2s_mode_t)(mode | I2S_MODE_DAC_BUILT_IN);
    }

    i2s_config_t i2s_config = {
        .mode = mode,
        .sample_rate = (uint32_t)sampleRate,
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
        .communication_format = i2s_comm_format_t(I2S_COMM_FORMAT_STAND_I2S),
        .intr_alloc_flags = ESP_INTR_FLAG_LEVEL1,
        .dma_buf_count = 8,
        .dma_buf_len = 1024,
        .use_apll = false,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0
    };

    esp_err_t err = i2s_driver_install(_port, &i2s_config, 0, NULL);
    if (err != ESP_OK) {
        return false;
    }

    if (!useInternalDAC) {
        i2s_pin_config_t pin_config = {
            .bck_io_num = bckPin,
            .ws_io_num = wsPin,
            .data_out_num = dataOutPin,
            .data_in_num = dataInPin
        };
        err = i2s_set_pin(_port, &pin_config);
        if (err != ESP_OK) {
            i2s_driver_uninstall(_port);
            return false;
        }
    } else {
        i2s_set_pin(_port, NULL);
    }

    _initialized = true;
    return true;
}

size_t I2S::read(void* dest, size_t size) {
    if (!_initialized) return 0;
    size_t bytes_read = 0;
    i2s_read(_port, dest, size, &bytes_read, portMAX_DELAY);
    return bytes_read;
}

