namespace RadDSP {

class FIR {
public:
    /**
     * @brief Constructor for FIR filter
     * @param coeffs Pointer to the FIR coefficients array
     * @param numCoeffs Number of taps (coefficients)
     */
    FIR(const float* coeffs, int numCoeffs);

    ~FIR();

    /**
     * @brief Process an array of samples
     * @param input Input buffer
     * @param output Output buffer (can be same as input)
     * @param length Number of samples to process
     * 
     * @note This implementation uses loop unrolling by 8 to leverage 
     * the ESP32 FPU registers for maximum performance.
     */
    void process(const float* input, float* output, int length);

private:
    float* _coeffs;
    float* _delayLine;
    int _numCoeffs;
};

} // namespace RadDSP

#endif // RAD_FIR_H
