"#ifndef RAD_CONTROL_H
#define RAD_CONTROL_H

#include <Arduino.h>

namespace RadDSP {

    /**
     * @brief Interface abstrak untuk modul DSP yang bisa dikontrol
     */
    class Controllable {
    public:
        // paramID: 0=Type, 1=Freq, 2=Gain, 3=Q (Tergantung implementasi modul)
        virtual void setParameter(uint8_t paramID, float value) = 0;
    };

    /**
     * @brief Controller untuk mem-parsing komando dari Serial dan I2C
     */
    class Controller {
    public:
        Controller();

        /**
         * @brief Mendaftarkan modul DSP ke dalam sistem kontrol
         * @param id ID unik untuk modul ini (0-255)
         * @param module Pointer ke objek filter (misal &eq1)
         */
        void attach(uint8_t id, Controllable* module);

        /**
         * @brief Mengaktifkan kontrol via Serial (Format: ID,Param,Value)
         */
        void beginSerial(long baudRate = 115200);

        /**
         * @brief Mengecek data masuk dari Serial. Panggil fungsi ini di dalam loop()!
         */
        void poll();

        /**
         * @brief Internal use: Mengeksekusi parameter ke modul yang dituju
         */
        void executeCommand(uint8_t id, uint8_t paramID, float value);

    private:
        Controllable* _modules[256];
        bool _serialEnabled;
        String _serialBuffer;
    };

}

#endif"

"#include "RadControl.h"
#include <Wire.h>

namespace RadDSP {

Controller* _globalController = nullptr;

void onI2CReceive(int numBytes) {
    if (!_globalController || numBytes < 6) {
        while(Wire.available()) Wire.read(); // Flush
        return;
    }

    uint8_t id = Wire.read();
    uint8_t param = Wire.read();

    union {
        uint8_t b[4];
        float f;
    } val;
    val.b[0] = Wire.read();
    val.b[1] = Wire.read();
    val.b[2] = Wire.read();
    val.b[3] = Wire.read();

    _globalController->executeCommand(id, param, val.f);

    while(Wire.available()) Wire.read(); // Flush sisanya
}

Controller::Controller() : _serialEnabled(false) {
    for (int i = 0; i < 256; i++) {
        _modules[i] = nullptr;
    }
    _globalController = this;
}

void Controller::attach(uint8_t id, Controllable* module) {
    if (id < 256) {
        _modules[id] = module;
    }
}

void Controller::beginSerial(long baudRate) {
    // Asumsi Serial.begin sudah dipanggil user atau kita panggil jika perlu.
    // Tapi amannya user yang memanggil Serial.begin di setup()
    _serialEnabled = true;
}

void Controller::beginI2C(uint8_t address, int sdaPin, int sclPin) {
    Wire.begin(address, sdaPin, sclPin, 400000);
    Wire.onReceive(onI2CReceive);
}

void Controller::executeCommand(uint8_t id, uint8_t paramID, float value) {
    if (id < 256 && _modules[id] != nullptr) {
        _modules[id]->setParameter(paramID, value);
    }
}

void Controller::poll() {
