122: // Fungsi audio (akan dijalankan terus menerus oleh RTOS Core)
123: void audioLoop() {
124:     // 1. Tarik 64 data sekaligus dari I2S DMA ke memori RAM
125:     if (i2s.readBlock()) {
126:         
127:         // 2. Ambil pointer array Kiri dan Kanan (sudah berbentuk Float -1.0 s/d 1.0)
128:         float* left = i2s.getLeftBuffer();
129:         float* right = i2s.getRightBuffer();
130:         
131:         // 3. Lakukan pemrosesan sinyal (contoh: EQ Peaking 1KHz)
132:         eqLeft.process(left, left, i2s.getBufferLength());
133:         
134:         // 4. Kirim kembali array yang sudah diproses ke I2S DMA
135:         i2s.writeBlock();
136:     }
137: }
138: 
139: void setup() {
140:     Serial.begin(115200);
141: 
142:     // Mendaftarkan EQ ke Controller dengan ID modul = 1
143:     dspControl.attach(1, &eqLeft);
144:     dspControl.beginSerial(115200);
145:     dspControl.beginI2C(0x40);
146: 
147:     // Inisialisasi sbg Master, 32-bit, MCLK GPIO 0, dmaBufCount=8, dmaBufLen=64.
148:     i2s.begin(I2S_NUM_0, 48000, 32, true, 26, 25, 33, 23, 0, false, 8, 64);
149:     
150:     // Set frekuensi awal EQ Biquad di 1000Hz, Gain -6dB, Q 1.5
151:     eqLeft.setPeakingEQ(1000.0f, -6.0f, 1.5f);
152: 
153:     // Mendelegasikan audioLoop ke Core 1. 
154:     // PERINGATAN: Argumen ke-3 (killArduinoLoop) diset FALSE agar void loop() 
155:     // tetap hidup dan bisa menjalankan dspControl.poll()
156:     RadDSP::startAudioTask(audioLoop, 1, false);
157: }
